/**
 * Cross-runtime phoneme timing parity test (WASM/JS).
 *
 * Loads tests/fixtures/phoneme_timing/golden_matrix.json (Python canonical
 * output) and verifies that this runtime's `durationsToTiming` produces
 * byte-equivalent results, within a tight float tolerance.
 *
 * Spec: docs/spec/phoneme-timing-contract.toml v1.0.
 * Fixture is regenerated by scripts/regenerate_timing_fixture.py.
 */

import { describe, it } from 'node:test';
import assert from 'node:assert/strict';
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';

import { durationsToTiming } from '../../src/timing.js';

const __dirname = dirname(fileURLToPath(import.meta.url));
const FIXTURE_PATH = resolve(
  __dirname,
  '../../../../../tests/fixtures/phoneme_timing/golden_matrix.json',
);

const fixture = JSON.parse(readFileSync(FIXTURE_PATH, 'utf-8'));

// Tolerance: Python uses 64-bit floats, JS Number is also 64-bit, so the
// arithmetic should agree to <1e-9. Allow 1e-6 to absorb any reordering.
const FLOAT_EPS = 1e-6;

const approxEqual = (actual, expected, eps = FLOAT_EPS) =>
  Math.abs(actual - expected) <= eps;

describe('phoneme timing parity (WASM/JS ↔ canonical Python)', () => {
  it('fixture loads with cases', () => {
    assert.strictEqual(fixture.schema_version, 1);
    assert.ok(Array.isArray(fixture.cases));
    assert.ok(fixture.cases.length > 0, 'fixture must have cases');
  });

  for (const caseDef of fixture.cases) {
    it(`case: ${caseDef.name} — ${caseDef.description ?? ''}`, () => {
      const { durations, phoneme_tokens, sample_rate, hop_length } =
        caseDef.inputs;
      const { phonemes: expectedPhonemes, total_duration_ms: expectedTotal,
        sample_rate: expectedSampleRate } = caseDef.expected;

      const result = durationsToTiming(
        durations,
        sample_rate,
        hop_length,
        phoneme_tokens.length > 0 ? phoneme_tokens : null,
      );

      assert.strictEqual(
        result.sample_rate,
        expectedSampleRate,
        'sample_rate mismatch',
      );
      assert.strictEqual(
        result.phonemes.length,
        expectedPhonemes.length,
        `phonemes count mismatch: got ${result.phonemes.length}, expected ${expectedPhonemes.length}`,
      );

      for (let i = 0; i < expectedPhonemes.length; i++) {
        const got = result.phonemes[i];
        const want = expectedPhonemes[i];
        assert.strictEqual(
          got.phoneme,
          want.phoneme,
          `[${caseDef.name}] phoneme[${i}] token mismatch`,
        );
        assert.ok(
          approxEqual(got.start_ms, want.start_ms),
          `[${caseDef.name}] phoneme[${i}].start_ms got=${got.start_ms} want=${want.start_ms}`,
        );
        assert.ok(
          approxEqual(got.end_ms, want.end_ms),
          `[${caseDef.name}] phoneme[${i}].end_ms got=${got.end_ms} want=${want.end_ms}`,
        );
        assert.ok(
          approxEqual(got.duration_ms, want.duration_ms),
          `[${caseDef.name}] phoneme[${i}].duration_ms got=${got.duration_ms} want=${want.duration_ms}`,
        );
      }

      assert.ok(
        approxEqual(result.total_duration_ms, expectedTotal),
        `[${caseDef.name}] total_duration_ms got=${result.total_duration_ms} want=${expectedTotal}`,
      );
    });
  }
});
